    for x, cell in enumerate(row):
        if cell != "#":
            walkable_cells.append((x, y))


def prey_of(team: str) -> str:
    if team == "W":
        return "F"
    if team == "F":
        return "P"
    return "W"


def predator_of(team: str) -> str:
    if team == "W":
        return "P"
    if team == "F":
        return "W"
    return "F"


def manhattan(x1: int, y1: int, x2: int, y2: int) -> int:
    return abs(x1 - x2) + abs(y1 - y2)


target_team = prey_of(my_team)
danger_team = predator_of(my_team)

while True:
    try:
        elementals_count = int(input().strip())
    except EOFError:
        break

    my_units = []
    prey_units = []
    predator_units = []

    for _ in range(elementals_count):
        elemental_id, team, x, y, prisoner = input().split()
        elemental_id = int(elemental_id)
        x = int(x)
        y = int(y)
        prisoner = int(prisoner) > 0

        if team == my_team:
            my_units.append((elemental_id, x, y, prisoner))
        elif team == target_team and not prisoner:
            prey_units.append((x, y))
        elif team == danger_team and not prisoner:
            predator_units.append((x, y))

    commands = []

    for elemental_id, x, y, prisoner in my_units:
        if prisoner:
            commands.append(f"{elemental_id} WAIT")
            continue

