                predator_units,
                key=lambda p: manhattan(x, y, p[0], p[1])
            )
            pred_dist = manhattan(x, y, px, py)

            if pred_dist <= 2:
                best_target = None
                best_score = None

                for tx, ty in walkable_cells:
                    score = manhattan(tx, ty, px, py)

                    if prey_units:
                        qx, qy = min(
                            prey_units,
                            key=lambda p: manhattan(tx, ty, p[0], p[1])
                        )
                        score -= 0.25 * manhattan(tx, ty, qx, qy)

                    if best_score is None or score > best_score:
                        best_score = score
                        best_target = (tx, ty)

                if best_target is not None:
                    commands.append(f"{elemental_id} MOVE {best_target[0]} {best_target[1]}")
                    continue

        # Otherwise, hunt nearest prey
        if prey_units:
            tx, ty = min(
                prey_units,
                key=lambda p: manhattan(x, y, p[0], p[1])
            )
            commands.append(f"{elemental_id} MOVE {tx} {ty}")
