import sys
import heapq

my_team = input().strip()  # "W", "F" or "P"
map_size = int(input().strip())

grid = []
walkable = set()
camp_pos = {}

for y in range(map_size):
    row = input().strip()
    grid.append(row)
    for x, cell in enumerate(row):
        if cell != "#":
            walkable.add((x, y))
        if cell in ("W", "F", "P"):
            camp_pos[cell] = (x, y)

DIRS = [(0, -1), (1, 0), (0, 1), (-1, 0)]


def prey_of(team: str) -> str:
    if team == "W":
        return "F"
    if team == "F":
        return "P"
    return "W"


def predator_of(team: str) -> str:
    if team == "W":
        return "P"
    if team == "F":
        return "W"
    return "F"


def manhattan(a, b) -> int:
    return abs(a[0] - b[0]) + abs(a[1] - b[1])


def neighbors(pos):
    x, y = pos
    for dx, dy in DIRS:
        np = (x + dx, y + dy)
        if np in walkable:
            yield np


def nearest(pos, targets):
    if not targets:
        return None
    return min(targets, key=lambda t: manhattan(pos, t))


def nearest_dist(pos, targets):
    if not targets:
        return 999999
    return min(manhattan(pos, t) for t in targets)


def build_risk_map(predator_units, ally_positions, reserved_targets):
    """
    Static local danger/crowding map for this turn.
    Lower is better.
    """
    risk = {}

    for cell in walkable:
        r = 1.0

        # Absolute danger: standing on a predator is forbidden
        if cell in predator_units:
            r += 10000.0

        # Strong penalty near predators
        d_pred = nearest_dist(cell, predator_units)
        if d_pred == 0:
            r += 10000.0
        elif d_pred == 1:
            r += 250.0
        elif d_pred == 2:
            r += 60.0
        elif d_pred == 3:
            r += 15.0

        # Anti-pack on current allied positions
        for p in ally_positions:
            d = manhattan(cell, p)
            if d == 0:
                r += 35.0
            elif d == 1:
                r += 18.0
            elif d == 2:
                r += 5.0

        # Anti-pack on already reserved targets this turn
        for p in reserved_targets:
            d = manhattan(cell, p)
            if d == 0:
                r += 200.0
            elif d == 1:
                r += 40.0
            elif d == 2:
                r += 8.0

        risk[cell] = r

    return risk


def weighted_next_step(start, goal, risk_map):
    """
    Dijkstra on cell risk.
    Returns first step from start to goal, or None if unreachable.
    """
    if start == goal:
        return start
    if goal not in walkable:
        return None

    pq = [(0.0, start)]
    dist = {start: 0.0}
    parent = {start: None}

    while pq:
        cur_cost, cur = heapq.heappop(pq)
        if cur_cost != dist[cur]:
            continue
        if cur == goal:
            break

        for nxt in neighbors(cur):
            # cost to enter nxt
            new_cost = cur_cost + risk_map[nxt]
            if nxt not in dist or new_cost < dist[nxt]:
                dist[nxt] = new_cost
                parent[nxt] = cur
                heapq.heappush(pq, (new_cost, nxt))

    if goal not in parent:
        return None

    cur = goal
    while parent[cur] is not None and parent[cur] != start:
        cur = parent[cur]

    return cur


def choose_hunt_goal(pos, prey_units, predator_units):
    """
    Choose distant prey target.
    Slightly prefer reachable, safe prey.
    """
    if not prey_units:
        return None

    best = None
    best_score = None

    for prey in prey_units:
        score = 0.0
        score += 3.0 * manhattan(pos, prey)
        score -= 1.5 * nearest_dist(prey, predator_units)
        if best_score is None or score < best_score:
            best_score = score
            best = prey

    return best


my_prey = prey_of(my_team)
my_predator = predator_of(my_team)
prison_camp = camp_pos[my_predator]  # where my prisoners are held

while True:
    try:
        elementals_count = int(input().strip())
    except EOFError:
        break

    my_units = []
    prey_units = []
    predator_units = []
    my_prisoner_count = 0

    for _ in range(elementals_count):
        elemental_id, team, x, y, prisoner = input().split()
        elemental_id = int(elemental_id)
        x = int(x)
        y = int(y)
        prisoner = int(prisoner) > 0

        pos = (x, y)

        if team == my_team:
            my_units.append({
                "id": elemental_id,
                "pos": pos,
                "prisoner": prisoner
            })
            if prisoner:
                my_prisoner_count += 1
        elif team == my_prey and not prisoner:
            prey_units.append(pos)
        elif team == my_predator and not prisoner:
            predator_units.append(pos)

    free_units = [u for u in my_units if not u["prisoner"]]

    # One rescuer only
    rescuer_id = None
    if my_prisoner_count > 0 and free_units:
        rescuer = min(free_units, key=lambda u: manhattan(u["pos"], prison_camp))
        rescuer_id = rescuer["id"]

    # Threatened units first
    def priority(u):
        return (nearest_dist(u["pos"], predator_units), u["id"])

    my_units.sort(key=priority)

    commands = []
    reserved_targets = set()

    current_free_positions = {
        u["id"]: u["pos"]
        for u in my_units
        if not u["prisoner"]
    }

    for unit in my_units:
        uid = unit["id"]
        pos = unit["pos"]

        if unit["prisoner"]:
            commands.append(f"{uid} WAIT")
            continue

        ally_positions = [
            p for other_id, p in current_free_positions.items()
            if other_id != uid
        ]

        risk_map = build_risk_map(predator_units, ally_positions, reserved_targets)

        pred = nearest(pos, predator_units)
        pred_dist = manhattan(pos, pred) if pred is not None else 999999

        # 1) FLEE
        if pred_dist <= 2:
            best_step = None
            best_score = None

            for step in [pos] + list(neighbors(pos)):
                score = 0.0
                score += 15.0 * nearest_dist(step, predator_units)
                score -= 2.0 * nearest_dist(step, prey_units)
                score -= risk_map[step]

                if best_score is None or score > best_score:
                    best_score = score
                    best_step = step

            if best_step is None or best_step == pos:
                commands.append(f"{uid} WAIT")
            else:
                reserved_targets.add(best_step)
                commands.append(f"{uid} MOVE {best_step[0]} {best_step[1]}")
            continue

        # 2) RESCUE
        if uid == rescuer_id:
            step = weighted_next_step(pos, prison_camp, risk_map)
            if step is None or step == pos:
                commands.append(f"{uid} WAIT")
            else:
                reserved_targets.add(step)
                commands.append(f"{uid} MOVE {step[0]} {step[1]}")
            continue

        # 3) HUNT
        hunt_goal = choose_hunt_goal(pos, prey_units, predator_units)
        if hunt_goal is not None:
            step = weighted_next_step(pos, hunt_goal, risk_map)
            if step is not None and step != pos:
                reserved_targets.add(step)
                commands.append(f"{uid} MOVE {step[0]} {step[1]}")
                continue

        commands.append(f"{uid} WAIT")

    print(";".join(commands) if commands else "0 WAIT")
